#!/usr/bin/env node
/**
 * Adversarial standing test for the ledger-staleness normalizer
 * (harness/ledger-staleness.mjs `fileTokens` / `staleFindings`).
 *
 * These cases were generated by a 4-lens adversarial skeptic panel (false
 * positive / false negative / encoding-edge / crash) run over the hardened
 * normalizer, then ADJUDICATED by hand: the panel proposes inputs, but the
 * `expect` below is the maintainer's call on what a CORRECT staleness check
 * should return — not the panel's. Guiding principle: a false NEGATIVE (missing
 * a changed file) is the dangerous direction; a false POSITIVE just costs one
 * extra re-audit, so ambiguous "is this a file list or prose?" inputs resolve
 * toward flagging.
 *
 * Two cases are DOCUMENTED OUT-OF-DOMAIN LIMITATIONS (marked `limitation`):
 * extension-less bare-filename joins ("Makefile and Dockerfile") and a Windows
 * absolute path with a repoRoot that is a SUBDIR of the real git top-level
 * (inconsistent with git's diff output). Neither occurs for this toolkit, whose
 * finders always emit real repo paths and which runs with repoRoot = the git
 * top-level. They are asserted at their accepted behavior so a future change
 * that "fixes" them is a conscious decision, not a silent drift.
 *
 * Dependency-free: `node acceptance/test-ledger-staleness-adversary.mjs`.
 */
import assert from 'node:assert/strict'
import { staleFindings, fileTokens } from '../harness/ledger-staleness.mjs'

let pass = 0, fail = 0
const check = (name, fn) => {
  try { fn(); pass++; console.log(`  ✓ ${name}`) }
  catch (e) { fail++; console.log(`  ✗ ${name}\n    ${String(e.message).split('\n').join('\n    ')}`) }
}

// Run one finding through staleFindings; return the flagged entry or null.
const run = (raw, changed, root) =>
  staleFindings([{ id: 'x', dimension: 'd', status: 'confirmed', file: raw }], changed, root || undefined)[0] || null

const C = 'force-app/main/default/classes/ForecastService.cls'

// [name, rawFile, changedFiles, repoRoot, expectStale]
const cases = [
  // ── false positives the conditional split + letter-ext check must NOT flag ──
  ['FP: "find and replace.js" dir-name word not split', 'src/find and replace.js:42', ['replace.js'], '', false],
  ['FP: "Command and Control" dir not fragmented', 'modules/Command and Control/run.py', ['Control/run.py'], '', false],
  ['FP: prose "the loader and cache.py" not flagged', 'Refactored the loader and cache.py', ['cache.py'], '', false],
  ['FP: "research and development" dir not fragmented', 'docs/research and development/spec.md', ['development/spec.md'], '', false],
  ['FP: version string "v2.0" not treated as a path', 'API contract and v2.0', ['v2.0'], '', false],
  ['FP: windows "command and query" dir not fragmented', 'src\\command and query\\bus.ts', ['query/bus.ts'], '', false],
  // ── deliberate safe over-flags (divergence from the panel, documented) ──
  ['over-flag: "a.ext and b.ext" is treated as a 2-file list', 'config.yaml and app.js', ['app.js'], '', true],
  ['over-flag: windows abs path suffix-matches via drive', 'C:\\code\\MyClass.cls', ['code/MyClass.cls'], '', true],
  // ── residual false negatives the location-suffix stripper must now catch ──
  ['FN: spaced comma ":5, 15-19" stripped', `${C}:5, 15-19`, [C], '', true],
  ['FN: github "#L7" anchor stripped', `${C}#L7`, [C], '', true],
  ['FN: "L"-prefixed ":L5" stripped', `${C}:L5`, [C], '', true],
  ['FN: parenthetical " (line 5)" stripped', `${C} (line 5)`, [C], '', true],
  ['FN: "&" multi-file join split', `server/index.js & ${C}:13`, [C], '', true],
  ['FN: comma multi-file join split', `server/index.js, ${C}:13`, [C], '', true],
  ['FN: abs path, no repoRoot → suffix match', '/abs/repo/server/index.js:42', ['server/index.js'], '', true],
  ['FN: abs path, embedded /./ collapsed + relativized', '/abs/repo/./server/index.js:42', ['server/index.js'], '/abs/repo', true],
  // ── encoding edges / controls ──
  ['edge: line:col ":5:13" stripped', 'src/Trigger.cls:5:13', ['src/Trigger.cls'], '', true],
  ['edge: path WITH a space survives (no internal split)', 'force-app/Acc Service.cls:8', ['force-app/Acc Service.cls'], '', true],
  ['edge: bare ":42" (only a line spec) → no token, no flag', ':42', ['src/Foo.cls'], '', false],
  ['edge: " AND " uppercase splits (case-insensitive)', 'config and src/App.cls:5 AND lib/Util.cls', ['lib/Util.cls'], '', true],
  ['edge: double-ext + range "report.tar.gz:100-120"', 'report.tar.gz:100-120', ['report.tar.gz'], '', true],
  ['edge: abs path, no repoRoot, 2 changed → suffix match', '/abs/repo/harness/index.js:10', ['harness/index.js', 'harness/ledger-staleness.mjs'], '', true],
  ['edge: array-stringified 2-file list (quotes/brackets)', `["${C}:13","force-app/main/default/classes/RiskService.cls:5"]`, ['force-app/main/default/classes/RiskService.cls'], '', true],
  ['edge: " and " INSIDE a real dir name is preserved', 'docs/sales and marketing/playbook.md:3', ['docs/sales and marketing/playbook.md'], '', true],
  ['edge: windows abs, no repoRoot, suffix match', 'C:\\Users\\dev\\proj\\force-app\\App.cls:10', ['force-app/App.cls'], '', true],
  ['edge: token == repoRoot → empty token, no flag, no crash', '/abs/repo:42', ['abs/repo'], '/abs/repo', false],
  // ── documented out-of-domain limitations (asserted at accepted behavior) ──
  ['limitation: extension-less "Makefile and Dockerfile" not flagged (accepted FN)', 'Makefile and Dockerfile', ['Dockerfile'], '', false],
  ['limitation: windows abs + subdir repoRoot not flagged (accepted FN)', 'C:\\src\\ForecastService.cls:13', ['src/ForecastService.cls'], 'C:/src', false],
]

console.log('ledger-staleness ADVERSARIAL test')
for (const [name, raw, changed, root, expectStale] of cases) {
  check(name, () => {
    const r = run(raw, changed, root)
    assert.equal(Boolean(r), expectStale, `expected stale=${expectStale}, got ${JSON.stringify(r)}`)
  })
}

// Display contract: for a multi-file cite, the reported `file` is the file that
// actually CHANGED, not the first cited path (which may be unchanged).
check('display: multi-file cite reports the MATCHED (changed) file', () => {
  const r = run(`${C}:1 and force-app/main/default/classes/RiskService.cls:2`, ['force-app/main/default/classes/RiskService.cls'], '')
  assert.ok(r, 'should be flagged stale')
  assert.equal(r.file, 'force-app/main/default/classes/RiskService.cls')
})

// fileTokens directly: the real two-file Lumina shape yields both clean paths.
check('fileTokens: real Lumina two-file shape → both repo-relative paths', () => {
  const toks = fileTokens('server/index.js:27 and /home/user/project/force-app/main/default/lwc/forecastPanel/forecastPanel.html:7', '/home/user/project')
  assert.deepEqual(toks, ['server/index.js', 'force-app/main/default/lwc/forecastPanel/forecastPanel.html'])
})

console.log(`\n${pass} passed, ${fail} failed`)
process.exit(fail ? 1 : 0)
